import * as feathersAuthentication from '@feathersjs/authentication';
import * as local from '@feathersjs/authentication-local';
import { disallow, discard, iff, isProvider, preventChanges } from 'feathers-hooks-common';
import { HookContext } from '@feathersjs/feathers';

const { authenticate } = feathersAuthentication.hooks;
const { hashPassword, protect } = local.hooks;

// Custom hook to check if user is admin
const isAdmin = async (context: HookContext): Promise<boolean> => {
  const { user } = context.params;
  return user && user.role === 'admin';
};

// Custom hook to validate email uniqueness
const validateUnique = async (context: HookContext): Promise<HookContext> => {
  const { data, service } = context;
  const existingUser = await service.find({
    query: { email: data.email },
    paginate: false
  });

  if (existingUser.length > 0) {
    throw new Error('Email already registered');
  }

  return context;
};

