import { HookContext, Application } from '@feathersjs/feathers';
import logger from './logger';

// Log all service calls
const logRequest = async (context: HookContext): Promise<HookContext> => {
  const { path, method, params, id } = context;
  const user = params.user ? `User: ${params.user.email}` : 'Anonymous';

  logger.info(`${method.toUpperCase()} ${path}${id ? `/${id}` : ''} - ${user}`);

  return context;
};

// Log execution time
const logTiming = async (context: HookContext): Promise<HookContext> => {
  const start = Date.now();

  // Store start time
  context.params = context.params || {};
  (context.params as any)._startTime = start;

  return context;
};

const logTimingAfter = async (context: HookContext): Promise<HookContext> => {
  const start = (context.params as any)?._startTime;
  if (start) {
    const duration = Date.now() - start;
    logger.info(`${context.path} ${context.method} took ${duration}ms`);
  }
  return context;
};

// Error logging
const logError = async (context: HookContext): Promise<HookContext> => {
  logger.error(`Error in ${context.path}:${context.method}`, context.error);
  return context;
};

